KAAAxC,OAAAiO,KAKnC,OAAAjD","file":"21.js","sourcesContent":["<template>\r\n    <el-dialog\r\n        :visible=\"showDialog\"\r\n        @open=\"open\"\r\n        @close=\"close\"\r\n        :title=\"`Detalle Orden N° ${row.id}`\"\r\n    >\r\n        <div class=\"row\" v-for=\"(data, idx) in row.orden_items\" :key=\"idx\">\r\n            <div class=\"col-2 text-center\">\r\n                {{ data.quantity }}\r\n            </div>\r\n            <div class=\"col-5 text-start\">\r\n                {{ data.food.description }}\r\n            </div>\r\n            <div class=\"col-2 text-end\">\r\n                {{ data.food.price }}\r\n            </div>\r\n\r\n            <div class=\"col-3 text-end\">\r\n                {{ (data.food.price * data.quantity).toFixed(2) }}\r\n            </div>\r\n        </div>\r\n        <div class=\"row\">\r\n            <hr />\r\n        </div>\r\n        <div class=\"row\">\r\n            <div class=\"col-9\"></div>\r\n            <div class=\"col-3 text-end\">S/ {{ this.total }}</div>\r\n        </div>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\nexport default {\r\n    props: [\"showDialog\", \"row\"],\r\n    data() {\r\n        return {\r\n            total: 0.0\r\n        };\r\n    },\r\n    created() {\r\n        this.getTotal();\r\n    },\r\n    methods: {\r\n        open() {\r\n            this.getTotal();\r\n        },\r\n        close() {\r\n            this.$emit(\"update:showDialog\", false);\r\n        },\r\n        getTotal() {\r\n            if (this.row.document) {\r\n                this.total = this.row.document.total;\r\n            }\r\n            if (this.row.sale_note) {\r\n                this.total = this.row.sale_note.total;\r\n            }\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// modules/Restaurant/Resources/assets/js/views/ordens/items.vue","/*\nobject-assign\n(c) Sindre Sorhus\n@license MIT\n*/\n\n'use strict';\n/* eslint-disable no-unused-vars */\nvar getOwnP