</a>\r\n                            </li>\r\n                            <li class=\"breadcrumb-item active\">\r\n                                <span class=\"text-muted\"\r\n                                    >Lista de Ordenes atentidas</span\r\n                                >\r\n                            </li>\r\n                        </ol>\r\n                    </div>\r\n                    <!-- <div class=\"col-12 col-md-6 d-flex align-items-start justify-content-end\">\r\n                 <button type=\"button\" class=\"btn btn-outline-primary btn-icon btn-icon-start w-100 w-md-auto\" @click.prevent=\"clickCreate()\">\r\n                <i class=\"icofont-plus-circle\"></i>\r\n                <span>Nuevo</span>\r\n                </button>\r\n             </div> -->\r\n                </div>\r\n            </div>\r\n        </div>\r\n        <div class=\"container-fluid p-l-0 p-r-0\">\r\n            <div class=\"card\" v-loading=\"loading\">\r\n                <div class=\"card-header bg-primary\">\r\n                    <h6 class=\"my-0 text-white\">Lista de Ordenes atentidas</h6>\r\n                </div>\r\n                <div class=\"card-body\">\r\n                    <div class=\"col-md-12 col-lg-12 col-xl-12 mb-2\">\r\n                        <div class=\"row\">\r\n                            <div class=\"col-md-4 col col-lg-4\">\r\n                                <label class=\"control-label\">Buscar por</label>\r\n                                <el-select\r\n                                    @change=\"reset\"\r\n                                    v-model=\"search.column\"\r\n                                    :key=\"1\"\r\n                                >\r\n                                    <el-option\r\n                                        v-for=\"(data, index) in columns\"\r\n                                        :key=\"index\"\r\n                                        :label=\"data.label\"\r\n                                        :value=\"data.value\"\r\n                                    ></el-option>\r\n                                </el-select>\r\n                            </div>\r\n                            <div\r\n                                v-if=\"search.column !== 'date'\"\r\n                                class=\"col-md-4 col col-lg-4 d-flex align-items-end\"\r\n                            >\r\n                                <el-input\r\n                                    :placeholder=\"\r\n                                        `${\r\n                                            search.column == 'orden'\r\n                                                ? 'N° de orden'\r\n                                                : 'Nombre / N° documento del cliente'\r\n                                        }`\r\n                                    \"\r\n                                    v-model=\"search.value\"\r\n                                >\r\n                                    <i\r\n                                        slot=\"prefix\"\r\n                                        class=\"el-icon-edit-outline\"\r\n                                    ></i\r\n                                ></el-input>\r\n                            </div>\r\n                            <div\r\n                                v-if=\"search.column == 'date'\"\r\n                                class=\"col-md-4 col col-lg-4 d-flex align-items-end\"\r\n                            >\r\n                                <el-date-picker\r\n                                    class=\"w-100\"\r\n                                    format=\"d/MM/yy\"\r\n                                    value-format=\"yyyy-MM-dd\"\r\n                                    v-model=\"search.value\"\r\n                                    type=\"date\"\r\n                                >\r\n                                </el-date-picker>\r\n                            </div>\r\n                            <div\r\n                                class=\"col-md-4 col col-lg-4 d-flex align-items-end\"\r\n                            >\r\n                                <button\r\n                                    @click=\"getData\"\r\n                                    class=\"btn btn-primary btn-sm\"\r\n                                    :loading=\"loading\"\r\n                                >\r\n                                    Buscar\r\n                                </button>\r\n                                <button\r\n                                    @click=\"DataFoods\"\r\n                                    class=\"btn btn-success btn-sm\"\r\n                                    :loading=\"loading\"\r\n                                >\r\n                                    Platos atentidos\r\n                                </button>\r\n                            </div>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"table-responsive\">\r\n                        <div>\r\n                            <el-pagination\r\n                                @current-change=\"getData\"\r\n                                layout=\"total, prev, pager, next\"\r\n                                :total=\"pagination.total\"\r\n                                :current-page.sync=\"pagination.current_page\"\r\n                                :page-size=\"pagination.per_page\"\r\n                            >\r\n                            </el-pagination>\r\n                        </div>\r\n                        <table class=\"table\" v-loading=\"loading\">\r\n                            <thead>\r\n                                <tr>\r\n                                    <th class=\"text-center\">#</th>\r\n                                    <th class=\"text-center\">N° de Comanda</th>\r\n                                    <th class=\"text-center\">Cliente</th>\r\n                                    <th class=\"text-center\">Detalle</th>\r\n                                    <th class=\"text-center\">Documento</th>\r\n                                    <th class=\"text-center\">Estado</th>\r\n                                    <th class=\"text-center\">Acciones</th>\r\n                                    <th class=\"text-center\">Total Pagado</th>\r\n                                </tr>\r\n                            </thead>\r\n                            <tbody>\r\n                                <tr\r\n                                    v-for=\"(row, index) in records\"\r\n                                    :key=\"index\"\r\n                                    :class=\"{\r\n                                        'bg bg-dark':\r\n                                            row.status_orden_id === '1',\r\n                                        'bg bg-secondary':\r\n                                            row.status_orden_id === '2',\r\n                                        'bg bg-warning':\r\n                                            row.status_orden_id === '3',\r\n                                        'bg-success':\r\n                                            row.status_orden_id === '4',\r\n                                        'bg bg-danger':\r\n                                            row.status_orden_id === '5'\r\n                                    }\"\r\n                                >\r\n                                    <td class=\"text-center\">{{ index + 1 }}</td>\r\n                                    <td class=\"text-center\">\r\n                                        {{ row.id }}\r\n                                    </td>\r\n\r\n                                    <td class=\"text-center\">\r\n                                        {{ row.customer }}\r\n                                    </td>\r\n\r\n                                    <td class=\"text-center\">\r\n                                        <button\r\n                                            class=\"btn btn-sm btn-primary\"\r\n                                            @click=\"viewItems(row)\"\r\n                                        >\r\n                                            <i class=\"fas fa-list\"></i>\r\n                                        </button>\r\n                                    </td>\r\n\r\n                                    <td class=\"text-center\">\r\n                                        {{ row.document_type }}<br />\r\n                                        <span\r\n                                            class=\"badge rounded-pill  text-dark\"\r\n                                        >\r\n                                            {{ row.document_number }}</span\r\n                                        ><br />\r\n\r\n                                        <button\r\n                                            class=\"btn btn-sm btn-success\"\r\n                                            @click=\"viewFile(row)\"\r\n                                            v-if=\"row.status_orden_id == 4\"\r\n                                        >\r\n                                            <i class=\"fas fa-file\"></i>\r\n                                            Descargar\r\n                                        </button>\r\n                                    </td>\r\n\r\n                                    <td class=\"text-center\">\r\n                                        {{ row.status }}\r\n                                    </td>\r\n\r\n                                    <td class=\"text-center\">\r\n                                        <el-button\r\n                                            v-if=\"\r\n                                                row.status_id == 1 ||\r\n                                                    row.status_id == 2\r\n                                            \"\r\n                                            type=\"danger\"\r\n                                            @click=\"anular_command(row.id)\"\r\n                                        >\r\n                                            Anular</el-button\r\n                                        >\r\n                                    </td>\r\n                                    <td class=\"text-center\">\r\n                                        {{ total(row) }}\r\n                                    </td>\r\n                                </tr>\r\n                            </tbody>\r\n                            <tr>\r\n                                <td colspan=\"7\" class=\"text-end\">\r\n                                    Total de Nota de Venta\r\n                                </td>\r\n                                <td class=\"text-center\">\r\n                                    {{ totals_notas.toFixed(2) }}\r\n                                </td>\r\n                            </tr>\r\n                            <tr>\r\n                                <td colspan=\"7\" class=\"text-end\">\r\n                                    Total de Boletas - Facturas\r\n                                </td>\r\n                                <td class=\"text-center\">\r\n                                    {{ totals_facturas.toFixed(2) }}\r\n                                </td>\r\n                            </tr>\r\n                            <tr>\r\n                                <td colspan=\"7\" class=\"text-end\">Total</td>\r\n                                <td class=\"text-center\">\r\n                                    {{ totals_efectivos.toFixed(2) }}\r\n                                </td>\r\n                            </tr>\r\n                        </table>\r\n\r\n                        <div>\r\n                            <el-pagination\r\n                                @current-change=\"getData\"\r\n                                layout=\"total, prev, pager, next\"\r\n                                :total=\"pagination.total\"\r\n                                :current-page.sync=\"pagination.current_page\"\r\n                                :page-size=\"pagination.per_page\"\r\n                            >\r\n                            </el-pagination>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n                <view-items\r\n                    v-if=\"currentRow\"\r\n                    :row=\"currentRow\"\r\n                    :showDialog.sync=\"showDialog\"\r\n                >\r\n                </view-items>\r\n                <ListFood\r\n                    :showDialogFoods.sync=\"showDialogFoods\"\r\n                    :listFoods.sync=\"listFoods\"\r\n                ></ListFood>\r\n            </div>\r\n        </div>\r\n    </div>\r\n</template>\r\n<style scoped>\r\n.file1 {\r\n    visibility: hidden;\r\n    position: absolute;\r\n}\r\n</style>\r\n<script>\r\nimport queryString from \"query-string\";\r\n\r\nimport ListFood from \"./listFoods.vue\";\r\nimport { deletable } from \"../../../../../../../resources/js/mixins/deletable\";\r\nimport ViewItems from \"./items.vue\";\r\nimport moment from \"moment\";\r\nexport default {\r\n    components: { ViewItems, ListFood },\r\n    mixins: [deletable],\r\n    props: [\"configuration\"],\r\n    data() {\r\n        return {\r\n            allRecords: [],\r\n            listFoods: {},\r\n            columns: [\r\n                {\r\n                    id: 1,\r\n                    value: \"id\",\r\n                    label: \"Número de orden\"\r\n                },\r\n                {\r\n                    id: 2,\r\n                    value: \"date\",\r\n                    label: \"Fecha\"\r\n                },\r\n                {\r\n                    id: 3,\r\n                    value: \"client\",\r\n                    label: \"Cliente (DNI / RUC)\"\r\n                }\r\n            ],\r\n            search: { column: \"date\", value: moment().format(\"YYYY-MM-DD\") },\r\n            date_start: moment().format(\"YYYY-MM-DD\"),\r\n            loading: false,\r\n            showDialog: false,\r\n            resource: \"ordens\",\r\n            currentRow: null,\r\n            showImage: false,\r\n            currentRecord: null,\r\n            currentImage: null,\r\n            areas: [],\r\n            pagination: {},\r\n            statusTable: [],\r\n            records: [],\r\n            totals_notas: 0,\r\n            totals_facturas: 0,\r\n            totals_efectivos: 0,\r\n            showDialogFoods: false\r\n        };\r\n    },\r\n    created() {\r\n        this.$eventHub.$on(\"reloadData\", () => {\r\n            this.getData();\r\n        });\r\n\r\n        this.getData();\r\n    },\r\n    methods: {\r\n        viewItems(row) {\r\n            this.currentRow = row;\r\n            this.showDialog = true;\r\n        },\r\n        anular_command(id) {\r\n            this.anular_comanda(\r\n                `/restaurant/worker/destroyorden/${id}`,\r\n                id\r\n            ).then(() => this.$eventHub.$emit(\"reloadData\"));\r\n        },\r\n        async DataFoods() {\r\n            const response = await this.$http.get(\r\n                `${this.resource}/listfoods/${this.search.value}`\r\n            );\r\n            this.listFoods = response.data;\r\n            this.showDialogFoods = true;\r\n        },\r\n        viewFile(row) {\r\n            let url = \"\";\r\n            if (row.document) {\r\n                let external_id = row.document.external_id;\r\n                url = `/downloads/document/pdf/${external_id}`;\r\n            }\r\n            if (row.sale_note) {\r\n                let external_id = row.sale_note.external_id;\r\n                url = `/sale-notes/print/${external_id}/a4`;\r\n            }\r\n            window.open(url, \"_blank\");\r\n        },\r\n        total(row) {\r\n            if (row.document) {\r\n                return row.document.total;\r\n            }\r\n            if (row.sale_note) {\r\n                return row.sale_note.total;\r\n            }\r\n            return 0.0;\r\n        },\r\n        getQueryParameters() {\r\n            return queryString.stringify({\r\n                page: this.pagination.current_page,\r\n                limit: this.limit,\r\n                ...this.search\r\n            });\r\n        },\r\n        reset() {\r\n            this.search.value = \"\";\r\n        },\r\n        Totals() {\r\n            let facturas = _.filter(this.records, { document_type_id: \"01\" });\r\n\r\n            let notas_venta = _.filter(this.records, {\r\n                document_type_id: \"80\"\r\n            });\r\n            console.log(\"notas_venta\", notas_venta);\r\n            console.log(\"facturas\", facturas);\r\n            console.log(\"this.records\", this.records);\r\n            this.totals_facturas = _.sumBy(facturas, it =>\r\n                parseFloat(it.total)\r\n            );\r\n            this.totals_notas = _.sumBy(notas_venta, it =>\r\n                parseFloat(it.total)\r\n            );\r\n            this.totals_efectivos = _.round(\r\n                this.totals_facturas + this.totals_notas,\r\n                2\r\n            );\r\n        },\r\n        async getData() {\r\n            this.loading = true;\r\n            //let query = queryString.stringify(this.search);\r\n            const response = await this.$http.get(\r\n                `${this.resource}/records?${this.getQueryParameters()}`\r\n            );\r\n            this.pagination = response.data.meta;\r\n            this.pagination.per_page = parseInt(response.data.meta.per_page);\r\n            this.records = response.data.data;\r\n            this.loading = false;\r\n            this.Totals();\r\n        },\r\n\r\n        clickDelete(id) {\r\n            this.destroy(`/${this.resource}/${id}`).then(() =>\r\n                this.$eventHub.$emit(\"reloadData\")\r\n            );\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// modules/Restaurant/Resources/assets/js/views/ordens/index.vue","<template>\r\n    <el-dialog\r\n        :visible=\"showDialog\"\r\n        @open=\"open\"\r\n        @close=\"close\"\r\n        :title=\"`Detalle Orden N° ${row.id}`\"\r\n    >\r\n        <div class=\"row\" v-for=\"(data, idx) in row.orden_items\" :key=\"idx\">\r\n            <div class=\"col-2 text-center\">\r\n                {{ data.quantity }}\r\n            </div>\r\n            <div class=\"col-5 text-start\">\r\n                {{ data.food.description }}\r\n            </div>\r\n            <div class=\"col-2 text-end\">\r\n                {{ data.food.price }}\r\n            </div>\r\n\r\n            <div class=\"col-3 text-end\">\r\n                {{ (data.food.price * data.quantity).toFixed(2) }}\r\n            </div>\r\n        </div>\r\n        <div class=\"row\">\r\n            <hr />\r\n        </div>\r\n        <div class=\"row\">\r\n            <div class=\"col-9\"></div>\r\n            <div class=\"col-3 text-end\">S/ {{ this.total }}</div>\r\n        </div>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\nexport default {\r\n    props: [\"showDialog\", \"row\"],\r\n    data() {\r\n        return {\r\n            total: 0.0\r\n        };\r\n    },\r\n    created() {\r\n        this.getTotal();\r\n    },\r\n    methods: {\r\n        open() {\r\n            this.getTotal();\r\n        },\r\n        close() {\r\n            this.$emit(\"update:showDialog\", false);\r\n        },\r\n        getTotal() {\r\n            if (this.row.document) {\r\n                this.total = this.row.document.total;\r\n            }\r\n            if (this.row.sale_note) {\r\n                this.total = this.row.sale_note.total;\r\n            }\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// modules/Restaurant/Resources/assets/js/views/ordens/items.vue","<template>\r\n    <div>\r\n       <div class=\"row\">\r\n             <el-dialog\r\n                title=\"Platos Atendidos\"\r\n                :visible.sync=\"showDialogFoods\"\r\n                  :before-close=\"closeDialog\">\r\n                <span>\r\n                    <form autocomplete=\"off\" @submit.prevent=\"submit\">\r\n                    <div class=\"form-body\">\r\n                        <div class=\"row\" v-loading=\"loading\">\r\n                              <div class=\"col-md-12\">\r\n                                <template v-if=\"listFoods.length>0\">\r\n                                <table class=\"table table-responsive\" >\r\n                                    <thead>\r\n                                        <tr>\r\n                                            <th class=\"text-center\">Cantidad</th>\r\n                                            <th>Producto</th>\r\n                                        </tr>\r\n                                    </thead>\r\n                                    <tbody>\r\n                                        <tr v-for=\"(row, index) in listFoods\" :key=\"index\">\r\n                                            <td  class=\"text-center\">{{row.move_quantity}}</td>\r\n                                             <td>{{row.description}}</td>\r\n                                         </tr>\r\n                                    </tbody>\r\n                                </table>\r\n                                </template>\r\n                                <template v-else>\r\n                                            No hay Productos\r\n                                </template>\r\n                              </div>\r\n\r\n                        </div>\r\n                    </div>\r\n                    </form>\r\n                </span>\r\n                <span slot=\"footer\" class=\"dialog-footer\">\r\n                    <el-button @click=\"closeDialog()\">Cerrar</el-button>\r\n                 </span>\r\n\r\n            </el-dialog>\r\n       </div>\r\n    </div>\r\n</template>\r\n<script>\r\n\r\n\r\n\r\n    export default {\r\n         props: ['showDialogFoods',\"listFoods\"],\r\n        data() {\r\n            return {\r\n                showDialog: false,\r\n                open_cash: true,\r\n                errors: {},\r\n                resource: 'restaurant/worker/cash',\r\n                date_closed:moment().format('YYYY-MM-DD'),\r\n                date_start: moment().format('YYYY-MM-DD'),\r\n                month_start: moment().format('YYYY-MM'),\r\n                final_balance:0,\r\n                cash:null,\r\n                loading:false\r\n            }\r\n        },\r\n\r\n        methods: {\r\n\r\n\r\n            closeDialog(){\r\n                 this.$emit('update:showDialogFoods', false)\r\n            },\r\n\r\n\r\n        }\r\n    }\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// modules/Restaurant/Resources/assets/js/views/ordens/listFoods.vue","exports = module.exports = require(\"../../../../../../../node_modules/css-loader/lib/css-base.js\")(true);\n// imports\n\n\n// module\nexports.push([module.id, \"\\n.file1[data-v-7645ebbd] {\\r\\n    visibility: hidden;\\r\\n    position: absolute;\\n}\\r\\n\", \"\", {\"version\":3,\"sources\":[\"C:/laragon/www/finalrestobar/modules/Restaurant/Resources/assets/js/views/ordens/modules/Restaurant/Resources/assets/js/views/ordens/index.vue\"],\"names\":[],\"mappings\":\";AA4PA;IACA,mBAAA;IACA,mBAAA;CACA\",\"file\":\"index.vue\",\"sourcesContent\":[\"<template>\\r\\n    <div>\\r\\n        <div class=\\\"container-fluid p-l-0 p-r-0\\\">\\r\\n            <div class=\\\"page-header\\\">\\r\\n                <div class=\\\"row\\\">\\r\\n                    <div class=\\\"col-sm-6\\\">\\r\\n                        <h6><span>Lista de Ordenes atentidas</span></h6>\\r\\n                        <ol class=\\\"breadcrumb\\\">\\r\\n                            <li class=\\\"breadcrumb-item\\\">\\r\\n                                <a href=\\\"/dashboard\\\">Dashboard</a>\\r\\n                            </li>\\r\\n                            <li class=\\\"breadcrumb-item active\\\">\\r\\n                                <span class=\\\"text-muted\\\"\\r\\n                                    >Lista de Ordenes atentidas</span\\r\\n                                >\\r\\n                            </li>\\r\\n                        </ol>\\r\\n                    </div>\\r\\n                    <!-- <div class=\\\"col-12 col-md-6 d-flex align-items-start justify-content-end\\\">\\r\\n                 <button type=\\\"button\\\" class=\\\"btn btn-outline-primary btn-icon btn-icon-start w-100 w-md-auto\\\" @click.prevent=\\\"clickCreate()\\\">\\r\\n                <i class=\\\"icofont-plus-circle\\\"></i>\\r\\n                <span>Nuevo</span>\\r\\n                </button>\\r\\n             </div> -->\\r\\n                </div>\\r\\n            </div>\\r\\n        </div>\\r\\n        <div class=\\\"container-fluid p-l-0 p-r-0\\\">\\r\\n            <div class=\\\"card\\\" v-loading=\\\"loading\\\">\\r\\n                <div class=\\\"card-header bg-primary\\\">\\r\\n                    <h6 class=\\\"my-0 text-white\\\">Lista de Ordenes atentidas</h6>\\r\\n                </div>\\r\\n                <div class=\\\"card-body\\\">\\r\\n                    <div class=\\\"col-md-12 col-lg-12 col-xl-12 mb-2\\\">\\r\\n                        <div class=\\\"row\\\">\\r\\n                            <div class=\\\"col-md-4 col col-lg-4\\\">\\r\\n                                <label class=\\\"control-label\\\">Buscar por</label>\\r\\n                                <el-select\\r\\n                                    @change=\\\"reset\\\"\\r\\n                                    v-model=\\\"search.column\\\"\\r\\n                                    :key=\\\"1\\\"\\r\\n                                >\\r\\n                                    <el-option\\r\\n                                        v-for=\\\"(data, index) in columns\\\"\\r\\n                                        :key=\\\"index\\\"\\r\\n                                        :label=\\\"data.label\\\"\\r\\n                                        :value=\\\"data.value\\\"\\r\\n                                    ></el-option>\\r\\n                                </el-select>\\r\\n                            </div>\\r\\n                            <div\\r\\n                                v-if=\\\"search.column !== 'date'\\\"\\r\\n                                class=\\\"col-md-4 col col-lg-4 d-flex align-items-end\\\"\\r\\n                            >\\r\\n                                <el-input\\r\\n                                    :placeholder=\\\"\\r\\n                                        `${\\r\\n                                            search.column == 'orden'\\r\\n                                                ? 'N° de orden'\\r\\n                                                : 'Nombre / N° documento del cliente'\\r\\n                                        }`\\r\\n                                    \\\"\\r\\n                                    v-model=\\\"search.value\\\"\\r\\n                                >\\r\\n                                    <i\\r\\n                                        slot=\\\"prefix\\\"\\r\\n                                        class=\\\"el-icon-edit-outline\\\"\\r\\n                                    ></i\\r\\n                                ></el-input>\\r\\n                            </div>\\r\\n                            <div\\r\\n                                v-if=\\\"search.column == 'date'\\\"\\r\\n                                class=\\\"col-md-4 col col-lg-4 d-flex align-items-end\\\"\\r\\n                            >\\r\\n                                <el-date-picker\\r\\n                                    class=\\\"w-100\\\"\\r\\n                                    format=\\\"d/MM/yy\\\"\\r\\n                                    value-format=\\\"yyyy-MM-dd\\\"\\r\\n                                    v-model=\\\"search.value\\\"\\r\\n                                    type=\\\"date\\\"\\r\\n                                >\\r\\n                                </el-date-picker>\\r\\n                            </div>\\r\\n                            <div\\r\\n                                class=\\\"col-md-4 col col-lg-4 d-flex align-items-end\\\"\\r\\n                            >\\r\\n                                <button\\r\\n                                    @click=\\\"getData\\\"\\r\\n                                    class=\\\"btn btn-primary btn-sm\\\"\\r\\n                                    :loading=\\\"loading\\\"\\r\\n                                >\\r\\n                                    Buscar\\r\\n                                </button>\\r\\n                                <button\\r\\n                                    @click=\\\"DataFoods\\\"\\r\\n                                    class=\\\"btn btn-success btn-sm\\\"\\r\\n                                    :loading=\\\"loading\\\"\\r\\n                                >\\r\\n                                    Platos atentidos\\r\\n                                </button>\\r\\n                            </div>\\r\\n                        </div>\\r\\n                    </div>\\r\\n                    <div class=\\\"table-responsive\\\">\\r\\n                        <div>\\r\\n                            <el-pagination\\r\\n                                @current-change=\\\"getData\\\"\\r\\n                                layout=\\\"total, prev, pager, next\\\"\\r\\n                                :total=\\\"pagination.total\\\"\\r\\n                                :current-page.sync=\\\"pagination.current_page\\\"\\r\\n                                :page-size=\\\"pagination.per_page\\\"\\r\\n                            >\\r\\n                            </el-pagination>\\r\\n                        </div>\\r\\n                        <table class=\\\"table\\\" v-loading=\\\"loading\\\">\\r\\n                            <thead>\\r\\n                                <tr>\\r\\n                                    <th class=\\\"text-center\\\">#</th>\\r\\n                                    <th class=\\\"text-center\\\">N° de Comanda</th>\\r\\n                                    <th class=\\\"text-center\\\">Cliente</th>\\r\\n                                    <th class=\\\"text-center\\\">Detalle</th>\\r\\n                                    <th class=\\\"text-center\\\">Documento</th>\\r\\n                                    <th class=\\\"text-center\\\">Estado</th>\\r\\n                                    <th class=\\\"text-center\\\">Acciones</th>\\r\\n                                    <th class=\\\"text-center\\\">Total Pagado</th>\\r\\n                                </tr>\\r\\n                            </thead>\\r\\n                            <tbody>\\r\\n                                <tr\\r\\n                                    v-for=\\\"(row, index) in records\\\"\\r\\n                                    :key=\\\"index\\\"\\r\\n                                    :class=\\\"{\\r\\n                                        'bg bg-dark':\\r\\n                                            row.status_orden_id === '1',\\r\\n                                        'bg bg-secondary':\\r\\n                                            row.status_orden_id === '2',\\r\\n                                        'bg bg-warning':\\r\\n                                            row.status_orden_id === '3',\\r\\n                                        'bg-success':\\r\\n                                            row.status_orden_id === '4',\\r\\n                                        'bg bg-danger':\\r\\n                                            row.status_orden_id === '5'\\r\\n                                    }\\\"\\r\\n                                >\\r\\n                                    <td class=\\\"text-center\\\">{{ index + 1 }}</td>\\r\\n                                    <td class=\\\"text-center\\\">\\r\\n                                        {{ row.id }}\\r\\n                                    </td>\\r\\n\\r\\n                                    <td class=\\\"text-center\\\">\\r\\n                                        {{ row.customer }}\\r\\n                                    </td>\\r\\n\\r\\n                                    <td class=\\\"text-center\\\">\\r\\n                                        <button\\r\\n                                            class=\\\"btn btn-sm btn-primary\\\"\\r\\n                                            @click=\\\"viewItems(row)\\\"\\r\\n                                        >\\r\\n                                            <i class=\\\"fas fa-list\\\"></i>\\r\\n                                        </button>\\r\\n                                    </td>\\r\\n\\r\\n                                    <td class=\\\"text-center\\\">\\r\\n                                        {{ row.document_type }}<br />\\r\\n                                        <span\\r\\n                                            class=\\\"badge rounded-pill  text-dark\\\"\\r\\n                                        >\\r\\n                                            {{ row.document_number }}</span\\r\\n                                        ><br />\\r\\n\\r\\n                                        <button\\r\\n                                            class=\\\"btn btn-sm btn-success\\\"\\r\\n                                            @click=\\\"viewFile(row)\\\"\\r\\n                                            v-if=\\\"row.status_orden_id == 4\\\"\\r\\n                                        >\\r\\n                                            <i class=\\\"fas fa-file\\\"></i>\\r\\n                                            Descargar\\r\\n                                        </button>\\r\\